/**
 * Agent job execution record (job_token intentionally omitted)
 */
export type AgentJob = {
    /**
     * Timestamp when the job completed
     */
    completedAt?: Date;
    /**
     * ID of the agent config that ran this job (from the frozen snapshot)
     */
    configId?: number;
    /**
     * Name of the agent config that ran this job (from the frozen snapshot)
     */
    configName?: string;
    /**
     * Frozen agent config at submit time
     */
    configSnapshot: unknown;
    /**
     * Docker container ID
     */
    containerId?: string;
    /**
     * Timestamp when the job was created
     */
    createdAt: Date;
    /**
     * Git provider comment/note ID for posted feedback
     */
    deliveryCommentId?: string;
    /**
     * Delivery status: null = not applicable, PENDING = awaiting delivery, DELIVERED = posted, FAILED = delivery error
     */
    deliveryStatus?: 'PENDING' | 'DELIVERED' | 'FAILED';
    /**
     * Human-readable error message
     */
    errorMessage?: string;
    /**
     * Container exit code
     */
    exitCode?: number;
    /**
     * Job ID
     */
    id: string;
    /**
     * Job type
     */
    jobType: 'PULL_REQUEST_REVIEW' | 'ISSUE_REVIEW' | 'CONVERSATION_REVIEW';
    /**
     * Tokens read from prompt cache
     */
    llmCacheReadTokens?: number;
    /**
     * Tokens written to prompt cache
     */
    llmCacheWriteTokens?: number;
    /**
     * Estimated cost in USD (agent-reported)
     */
    llmCostUsd?: number;
    /**
     * LLM model used (e.g. gpt-5.4-mini, claude-sonnet-4-5)
     */
    llmModel?: string;
    /**
     * Model version/snapshot date (e.g. 2026-03-17)
     */
    llmModelVersion?: string;
    /**
     * Total LLM API calls (steps) during execution
     */
    llmTotalCalls?: number;
    /**
     * Total input tokens consumed
     */
    llmTotalInputTokens?: number;
    /**
     * Total output tokens generated
     */
    llmTotalOutputTokens?: number;
    /**
     * Total reasoning/thinking tokens
     */
    llmTotalReasoningTokens?: number;
    /**
     * Job metadata (routing/display info)
     */
    metadata?: unknown;
    /**
     * Job output (agent results)
     */
    output?: unknown;
    /**
     * Number of retry attempts
     */
    retryCount: number;
    /**
     * Timestamp when the job started running
     */
    startedAt?: Date;
    /**
     * Current job status
     */
    status: 'QUEUED' | 'RUNNING' | 'COMPLETED' | 'FAILED' | 'TIMED_OUT' | 'CANCELLED';
};

